package ru.memearena.security; import org.springframework.security.core.Authentication; import org.springframework.security.core.context.SecurityContextHolder; public final class CurrentUser{private CurrentUser(){} public static AuthenticatedUserPrincipal required(){Authentication a=SecurityContextHolder.getContext().getAuthentication(); if(a==null||!(a.getPrincipal() instanceof AuthenticatedUserPrincipal p)) throw new ru.memearena.error.ApiException(org.springframework.http.HttpStatus.UNAUTHORIZED,ru.memearena.error.ErrorCode.AUTHENTICATION_REQUIRED,"Authentication required"); return p;}}
